namespace InventoryApp.Services;

public record EquipmentItem(int Id, string Name, string Location, DateOnly LastInspected);

public class EquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate a slow data source
        await Task.Delay(500);

        return
        [
            new(1, "Hydraulic Press",    "Building A - Bay 3",  new DateOnly(2026, 4, 10)),
            new(2, "CNC Lathe",          "Building B - Shop 1", new DateOnly(2026, 3, 22)),
            new(3, "Forklift #7",        "Warehouse C",         new DateOnly(2026, 5, 1)),
            new(4, "Overhead Crane",     "Building A - Bay 1",  new DateOnly(2025, 12, 15)),
            new(5, "Welding Station 2",  "Building B - Shop 3", new DateOnly(2026, 2, 28)),
            new(6, "Air Compressor",     "Utility Room",        new DateOnly(2026, 5, 18)),
            new(7, "Band Saw",           "Building A - Bay 2",  new DateOnly(2026, 1, 9)),
        ];
    }
}

@page "/inventory"
@rendermode InteractiveServer
@inject InventoryApp.Services.EquipmentService EquipmentService
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? items;
    private PersistingComponentStateSubscription persistingSubscription;

    protected override async Task OnInitializedAsync()
    {
        persistingSubscription = ApplicationState.RegisterOnPersisting(PersistData);

        if (!ApplicationState.TryTakeFromJson<List<EquipmentItem>>("inventory", out var restored))
        {
            // First render (prerender): fetch from the service
            items = await EquipmentService.GetEquipmentAsync();
        }
        else
        {
            // Interactive render: reuse data that was already fetched
            items = restored;
        }
    }

    private Task PersistData()
    {
        ApplicationState.PersistAsJson("inventory", items);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        persistingSubscription.Dispose();
    }
}

